actions.script:
import groovy.json.JsonOutput import groovy.json.JsonSlurper
def runValue = ec.entity.find('moqui.math.MathModelRun').condition('mathModelRunId', mathModelRunId).one() if (!runValue) throw new IllegalArgumentException("MathModelRun not found for ${mathModelRunId}") runValue = runValue.cloneValue()
JsonSlurper slurper = new JsonSlurper() Map currentResults = runValue.results ? (slurper.parseText(runValue.results) as Map) : [:] currentResults.metrics = metricsJson instanceof Map ? metricsJson : (metricsJson ? slurper.parseText(metricsJson.toString()) : [:]) if (statusId) currentResults.statusHint = statusId runValue.results = JsonOutput.toJson(currentResults) runValue.update()

import groovy.json.JsonOutput import groovy.json.JsonSlurper
def runValue = ec.entity.find('moqui.math.MathModelRun').condition('mathModelRunId', mathModelRunId).one() if (!runValue) throw new IllegalArgumentException("MathModelRun not found for ${mathModelRunId}") runValue = runValue.cloneValue()
JsonSlurper slurper = new JsonSlurper() Map currentResults = runValue.results ? (slurper.parseText(runValue.results) as Map) : [:] currentResults.summary = resultSummaryJson instanceof Map ? resultSummaryJson : (resultSummaryJson ? slurper.parseText(resultSummaryJson.toString()) : [:]) runValue.results = JsonOutput.toJson(currentResults) runValue.endDate = ec.user.nowTimestamp runValue.runningTimeMillis = runValue.startTime ? ((runValue.endDate.time - runValue.startTime.time) as BigDecimal) : null runValue.hasError = 'N' runValue.update()

import groovy.json.JsonOutput import groovy.json.JsonSlurper
def runValue = ec.entity.find('moqui.math.MathModelRun').condition('mathModelRunId', mathModelRunId).one() if (!runValue) throw new IllegalArgumentException("MathModelRun not found for ${mathModelRunId}") runValue = runValue.cloneValue()
JsonSlurper slurper = new JsonSlurper() Map currentResults = runValue.results ? (slurper.parseText(runValue.results) as Map) : [:] if (metricsJson) currentResults.metrics = metricsJson instanceof Map ? metricsJson : slurper.parseText(metricsJson.toString()) runValue.results = JsonOutput.toJson(currentResults) runValue.endDate = ec.user.nowTimestamp runValue.runningTimeMillis = runValue.startTime ? ((runValue.endDate.time - runValue.startTime.time) as BigDecimal) : null runValue.hasError = 'Y' runValue.errors = errorMessage ?: 'Math model run failed' runValue.update()

String effectiveMathModelId = (mathModelId ?: 'AgentMoquiRagModel_v1').toString()
def modelValue = ec.entity.find('moqui.math.MathModel').condition('mathModelId', effectiveMathModelId).one()
if (!modelValue) throw new IllegalArgumentException("MathModel not found for ${effectiveMathModelId}")
def modelDef = ec.entity.find('moqui.math.MathModelDef').condition('mathModelDefId', modelValue.mathModelDefId).one()
List childDefs = ec.entity.find('moqui.math.MathModelDef').condition('parentModelDefId', modelValue.mathModelDefId).list()
List modelDefIds = [modelValue.mathModelDefId]
childDefs.each { if (it?.mathModelDefId) modelDefIds.add(it.mathModelDefId as String) }
List contents = ec.entity.find('moqui.math.MathModelDefContent')
        .condition('mathModelDefId', 'in', modelDefIds)
        .list()
List identifications = ec.entity.find('moqui.math.MathModelDefIdentification')
        .condition('mathModelDefId', 'in', modelDefIds)
        .list()
List runs = ec.entity.find('moqui.math.MathModelRun').condition('mathModelId', effectiveMathModelId).orderBy('-startTime').list().take(20)
List modelData = ec.entity.find('moqui.math.MathModelData').condition('mathModelId', effectiveMathModelId).orderBy('-fromDate').list().take(50)
Set tensorIds = [] as Set
modelData.each { if (it?.tensorId) tensorIds.add(it.tensorId as String) }
List tensorContents = tensorIds ? ec.entity.find('moqui.math.TensorContent')
        .condition('tensorId', 'in', tensorIds as List)
        .list() : []
List graphContents = modelValue.graphId ? ec.entity.find('moqui.math.GraphContent')
        .condition('graphId', modelValue.graphId)
        .list() : []
Map runDataGroupedByRun = [:].withDefault { [inputs: [], outputs: [], tensors: [], graphs: []] }
modelData.each { md ->
    if (!md?.generatedByRunId) return
    Map bucket = runDataGroupedByRun[md.generatedByRunId as String]
    if (md.dataTypeEnumId == 'MmdtTensor') {
        bucket.tensors.add(md)
    } else if (md.graphVertexId || md.graphEdgeId) {
        bucket.graphs.add(md)
    } else if (md.purposeEnumId == 'MmdpModelInputs') {
        bucket.inputs.add(md)
    } else {
        bucket.outputs.add(md)
    }
}
def latestIndexRun = runs.find { ((it?.parameters ?: '') as String).contains('Index') || ((it?.messages ?: '') as String).contains('Index') }
def latestGraphLoadRun = runs.find { ((it?.parameters ?: '') as String).contains('ArtifactGraphLoad') || ((it?.messages ?: '') as String).contains('ArtifactGraph') }
def latestEvaluationRun = runs.find { ((it?.parameters ?: '') as String).contains('Evaluation') || ((it?.messages ?: '') as String).contains('Evaluation') }

lineage = [
    mathModel : modelValue,
    modelDef : modelDef,
    modelDefIds : modelDefIds,
    childModelDefs : childDefs,
    modelContents : contents,
    modelIdentifications : identifications,
    recentRuns : runs,
    recentModelData : modelData,
    tensorContents : tensorContents,
    graphContents : graphContents,
    runDataGroupedByRun : runDataGroupedByRun,
    latestIndexRun : latestIndexRun,
    latestGraphLoadRun : latestGraphLoadRun,
    latestEvaluationRun : latestEvaluationRun
]
